    try {
      await fetch(API+'/room-doors/'+id,{method:'DELETE'});
      setRoomDoors(prev=>prev.filter(d=>d.id!==id));
    } catch(e) { setRoomDoors(prev=>prev.filter(d=>d.id!==id)); }
