                              <div style={{padding:'10px',backgroundColor:'white',borderRadius:'8px'}}><p style={{color:C.textSec,fontSize:'11px',margin:'0 0 2px'}}>Все расходы</p><b style={{color:C.danger,fontSize:'15px'}}>{total.toLocaleString()+' ₽'}</b></div>
