                            <button onClick={async()=>{if(!window.confirm('Удалить документ?'))return;await fetch(API+'/project-documents/'+d.id,{method:'DELETE'});await loadAll();}} style={{...btnR,padding:'4px 8px'}}><Trash2 size={11}/></button>
